export default OrderModal;

import React, { useState, useMemo } from 'react';
import { LEADS } from '../constants';
import { BarChart, Users, Target, Activity, MessageSquare, TrendingUp, Info, Zap, ChevronRight, Mail, CheckSquare, Square, X, Sparkles, Send, Loader2, CheckCircle2 } from 'lucide-react';
import { BarChart as ReBarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { GoogleGenAI } from '@google/genai';

const CRMPage: React.FC = () => {
  const [selectedLeadIds, setSelectedLeadIds] = useState<string[]>([]);
  const [isCampaignModalOpen, setIsCampaignModalOpen] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isSending, setIsSending] = useState(false);
  const [campaignSuccess, setCampaignSuccess] = useState(false);
  const [campaignData, setCampaignData] = useState({
    subject: '',
    body: ''
  });

  const chartData = [
    { name: 'Juil', val: 40 },
    { name: 'Août', val: 55 },
    { name: 'Sept', val: 80 },
    { name: 'Oct', val: 70 },
    { name: 'Nov', val: 90 },
    { name: 'Déc', val: 100 },
  ];

  const selectedLeads = useMemo(() => 
    LEADS.filter(l => selectedLeadIds.includes(l.id)),
    [selectedLeadIds]
  );

  const toggleLeadSelection = (id: string) => {
    setSelectedLeadIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const toggleSelectAll = () => {
    if (selectedLeadIds.length === LEADS.length) {
      setSelectedLeadIds([]);
    } else {
      setSelectedLeadIds(LEADS.map(l => l.id));
    }
  };

  const generateAIEmail = async () => {
    if (selectedLeads.length === 0) return;
    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const targetEntities = selectedLeads.map(l => l.entity).join(', ');
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Génère un email de relance commerciale ultra-performant pour les entreprises suivantes : ${targetEntities}. 
        Le ton doit être celui de Krypton AI : autoritaire, stratégique et haut de gamme. 
        Focus sur l'activation de la "Porte Krypton" (IA de closing).
        Réponds au format texte avec :
        OBJET: [Sujet]
        CORPS: [Contenu]`,
        config: {
          temperature: 0.8,
        }
      });

      const text = response.text || "";
      const subjectMatch = text.match(/OBJET:\s*(.*)/i);
      const bodyMatch = text.match(/CORPS:\s*([\s\S]*)/i);

      setCampaignData({
        subject: subjectMatch ? subjectMatch[1].trim() : 'Opportunité Stratégique Krypton AI',
        body: bodyMatch ? bodyMatch[1].trim() : text
      });
    } catch (error) {
      console.error('Email Generation Error:', error);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSendCampaign = () => {
    setIsSending(true);
    setTimeout(() => {
      setIsSending(false);
      setCampaignSuccess(true);
      setTimeout(() => {
        setCampaignSuccess(false);
        setIsCampaignModalOpen(false);
        setSelectedLeadIds([]);
      }, 3000);
    }, 2000);
  };

  return (
    <div className="max-w-7xl mx-auto px-6 pt-32 pb-12">
      <div className="flex flex-col lg:flex-row justify-between items-end mb-12 gap-6">
        <div>
          <div className="flex items-center gap-3 mb-2">
