                    <button 
                      onClick={generateAIEmail}
                      disabled={isGenerating}
                      className="flex-grow py-6 border border-[#E10600]/30 bg-[#E10600]/5 text-[#E10600] font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-4 hover:bg-[#E10600] hover:text-white transition-all group"
                    >
                      {isGenerating ? <Loader2 className="animate-spin" size={16} /> : <><Sparkles size={16} className="group-hover:rotate-12 transition-transform" /> GÉNÉRER PAR IA</>}
                    </button>
                    <button 
                      onClick={handleSendCampaign}
                      disabled={isSending || !campaignData.subject || !campaignData.body}
                      className="flex-grow py-6 bg-[#E10600] text-white font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-4 hover:bg-red-700 transition-all shadow-xl shadow-red-500/20 disabled:opacity-50"
                    >
                      {isSending ? <Loader2 className="animate-spin" size={16} /> : <><Send size={16} /> DÉPLOYER CAMPAGNE</>}
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

